  { code: "kr-region-229", name: "제주시", engName: "Jeju-si", logo: "https://commons.wikimedia.org/wiki/Special:FilePath/Emblem_of_Jeju.svg", capital: "한라산, 돌하르방", continent: "제주특별자치도", location: "제주 북부", trivia: "제주도의 관문인 국제공항이 있고 섬 한가운데 우뚝 솟은 백록담을 품은 한라산과 곶자왈 등 천혜의 화산 생태계가 살아 숨 쉬는 세계 자연 유산입니다.", landmarks: ["한라산 국립공원", "용두암", "동문시장"] },
  { code: "kr-region-230", name: "서귀포시", engName: "Seogwipo-si", logo: "https://commons.wikimedia.org/wiki/Special:FilePath/Emblem_of_Seogwipo.svg", capital: "감귤, 폭포, 성산일출봉", continent: "제주특별자치도", location: "제주 남부", trivia: "따뜻한 기후 덕분에 노랗고 달콤한 감귤이 탐스럽게 자라며 바다로 떨어지는 웅장한 정방폭포와 바다 위로 솟아오른 거대한 화산 분화구 성산일출봉이 환상적입니다.", landmarks: ["성산일출봉", "천지연폭포", "중문관광단지"] }
